27	
28	`undef SYNC_PL_NOSYNTHESIS_NOSYNTH_GCS
29	`ifndef SYNC_PL_NO_RANDOMIZATION
30	`ifndef SYNTH_LEVEL1_COMPILE
31	`ifndef SYNTHESIS
32	    `define SYNC_PL_NOSYNTHESIS_NOSYNTH_GCS
33	`endif
34	`endif
35	`endif
36	
37	// VCS coverage off
38	
39	`ifdef  SYNC_PL_NOSYNTHESIS_NOSYNTH_GCS
40	reg [0:0] RandSyncBusPipe [0:1];
41	reg [0:0] RandSyncBusCurr;
42	reg [0:0] RandSyncBusNext;
43	reg [0:0] RandSyncBusRand;
44	reg [0:0] RandSyncBusPick;
45	reg [1:1] RandSyncBusKnown;
46	reg [1:1] RandSyncBusDelta;
47	reg       RandSyncEnable;
48	reg       RandSyncBusEnable;
49	reg       RandSyncBitEnable;
50	reg       RandSyncDiff;
51	reg       RandSyncDone;
52	reg       RandSyncSnap;
53	reg       RandSyncEval;
54	`endif
55	// VCS coverage on
56	
57	// input bus
58	
59	wire sync_ibus_preDFTxclamp; 
60	wire dft_xclamp_hold_mux_s_sync_i;
61	wire dft_xclamp_hold_mux_i1_sync_i;
62	assign sync_ibus_preDFTxclamp = sync_i     ;
63	NV_BLKBOX_SRC0 UJ_dft_xclamp_ctrl_hold_sync_i (.Y(dft_xclamp_hold_mux_s_sync_i) );
64	NV_BLKBOX_SRC0 UJ_dft_xclamp_scan_hold_sync_i (.Y(dft_xclamp_hold_mux_i1_sync_i) );
65	MUX2HDD2 UJ_FP_MUX_sync_i_dft_xclamp_before_sync (
66	  .S  (dft_xclamp_hold_mux_s_sync_i),
67	  .I0 (sync_ibus_preDFTxclamp),
68	  .I1 (dft_xclamp_hold_mux_i1_sync_i),
69	  .Z (sync_ibus)
70	);
71	
72	// random bus
73	
74	`ifdef SYNC_PL_NOSYNTHESIS_NOSYNTH_GCS
75	  assign sync_rbus = RandSyncBusRand;
76	`else 
77	  assign sync_rbus = sync_ibus;
78	`endif
79	
80	// buffer bus
81	
82	assign sync_bbus = sync_rbus;
83	
84	// sync bus
85	
86	
87	sync3d sync_0 (
88	  .clk(clk), 
89	  .d(sync_bbus[0]),
90	  .q(sync_sbus[0])
91	  );
92	
93	// defeating sync randomizer
94	`ifndef NO_PLI_OR_EMU
95	`ifndef GATES
96	`ifdef SYNC_PL_NOSYNTHESIS_NOSYNTH_GCS
97	
98	  `ifdef NVTOOLS_SYNC2D_GENERIC_CELL
99	  defparam sync_0.NV_GENERIC_CELL.first_stage_of_sync.mode = 0;
100	  `else
101	  defparam sync_0.first_stage_of_sync.mode = 0;
102	  `endif
103	
104	`endif
105	`endif
106	`endif
107	
108	// output bus
109	
110	assign sync_o = sync_sbus;
111	
112	// VCS coverage off
113	`ifndef NO_PLI_OR_EMU
114	`ifdef SYNC_PL_NOSYNTHESIS_NOSYNTH_GCS
115	initial begin
116	  if ($test$plusargs("RandSyncInfo")) $display ("INFO: RandSync:  @ %m");
117	end
118	initial begin
119	  RandSyncEnable = 1'b1;
120	  if ($test$plusargs("RandSyncGlobalDisable")) RandSyncEnable = 1'b0;
121	  if ($test$plusargs("RandSyncLocalDisable")) RandSyncEnable = 1'b0;
122	end
123	
124	// SRC before DSTCLK: new SRC is sampled to CUR, CUR is sampled to PRE, CUR/PRE are randomized.
125	// SRC equals DSTCLK: new SRC is sampled to CUR, CUR is sampled to PRE, CUR/PRE are randomized.
126	// SRC after  DSTCLK: old SRC is sampled again to CUR (NOP), CUR is sampled to PRE, CUR == PRE.
127	
128	// curr 
129	always @(sync_ibus) begin
130	  RandSyncBusCurr <= sync_ibus;
131	end
132	
133	
134	
135	
136	// snap (glitch filter)
137	initial RandSyncSnap = 1'b0;
138	always @(posedge clk) begin 
139	  RandSyncSnap <= (RandSyncSnap === 1'bx)? 1'b0 : !RandSyncSnap; 
140	end
141	
142	// eval (glitch filter)
143	initial RandSyncEval = 1'b0;
144	always @(RandSyncBusCurr) begin 
145	  RandSyncEval <= (RandSyncEval === 1'bx)? 1'b0 : !RandSyncEval; 
146	end
147	
148	// eval 
149	always @(RandSyncEval or RandSyncSnap) begin: rand_sync_block
150	  integer i, j;
151	
152	  // bump
153	  for (i=1; i>=1; i=i-1) begin
154	    RandSyncBusPipe[i] = RandSyncBusPipe[i-1];
155	  end
156	  RandSyncBusPipe[0] = RandSyncBusCurr; 
157	
158	  // next
159	  RandSyncBusNext = RandSyncBusPipe[0]; 
160	
161	  // rand 
162	  if (RandSyncEnable) begin
163	    // known
164	    for (i=1; i>=1; i=i-1) begin
165	      RandSyncBusKnown[i] = |RandSyncBusPipe[i] !== 1'bx;
166	    end
167	    // delta
168	    for (i=1; i>=1; i=i-1) begin
169	      RandSyncBusDelta[i] = |(RandSyncBusPipe[i] ^ RandSyncBusPipe[i-1]);
170	    end
171	    if (&RandSyncBusKnown && |RandSyncBusDelta) begin 
172	      RandSyncBusNext = RandSyncBusPipe[1]; 
173	      RandSyncBusEnable = prand_inst0(1, 100) > (100 - 50);
174	      if (RandSyncBusEnable) begin 
175	        RandSyncDone = 1'b0;
176	        for (i=1; i>=1; i=i-1) begin
177	          RandSyncDiff = RandSyncBusPipe[i] !== RandSyncBusPipe[i-1];
178	          if (RandSyncDiff && !RandSyncDone) begin
179	            RandSyncBusPickTask (RandSyncBusPipe[i], RandSyncBusPipe[i-1]);
180	            if (RandSyncBusNext !== RandSyncBusPick) begin
181	              RandSyncBusNext = RandSyncBusPick;
182	              RandSyncDone = 1'b1;
183	            end
184	          end
185	        end
186	      end
187	    end
188	  end
189	  RandSyncBusRand = RandSyncBusNext;
190	end
191	
192	// task
193	task RandSyncBusPickTask; // rand value = mixture
194	  input [0:0] RandSyncTaskBusPrev;
195	  input [0:0] RandSyncTaskBusCurr;
196	  integer i;
197	  for (i=0; i<=0; i=i+1) begin
198	    if (RandSyncTaskBusCurr[i] === RandSyncTaskBusPrev[i]) begin
199	      RandSyncBusPick[i] = RandSyncTaskBusCurr[i];
200	    end else begin
201	      RandSyncBitEnable = prand_inst1(1, 100) > (100 - 50);
202	      RandSyncBusPick[i] = (RandSyncBitEnable)? RandSyncTaskBusCurr[i] : RandSyncTaskBusPrev[i];
203	    end
204	  end
205	endtask
206	
207	
208	`ifdef SYNTH_LEVEL1_COMPILE
209	`else
210	`ifdef SYNTHESIS
211	`else
212	`ifdef PRAND_VERILOG
213	// Only verilog needs any local variables
214	reg [47:0] prand_local_seed0;
215	reg prand_initialized0;
216	reg prand_no_rollpli0;
217	`endif
218	`endif
219	`endif
220	
221	function [31:0] prand_inst0;
222	//VCS coverage off
223	    input [31:0] min;
224	    input [31:0] max;
225	    reg [32:0] diff;
226	    
227	    begin
228	`ifdef SYNTH_LEVEL1_COMPILE
229	        prand_inst0 = min;
230	`else
231	`ifdef SYNTHESIS
232	        prand_inst0 = min;
233	`else
234	`ifdef PRAND_VERILOG
235	        if (prand_initialized0 !== 1'b1) begin
236	            prand_no_rollpli0 = $test$plusargs("NO_ROLLPLI");
237	            if (!prand_no_rollpli0)
238	                prand_local_seed0 = {$prand_get_seed(0), 16'b0};
239	            prand_initialized0 = 1'b1;
240	        end
241	        if (prand_no_rollpli0) begin
242	            prand_inst0 = min;
243	        end else begin
244	            diff = max - min + 1;
245	            prand_inst0 = min + prand_local_seed0[47:16] % diff;
246	            // magic numbers taken from Java's random class (same as lrand48)
247	            prand_local_seed0 = prand_local_seed0 * 48'h5deece66d + 48'd11;
248	        end
249	`else
250	`ifdef PRAND_OFF
251	        prand_inst0 = min;
252	`else
253	        prand_inst0 = $RollPLI(min, max, "auto");
254	`endif
255	`endif
256	`endif
257	`endif
258	    end
259	//VCS coverage on
260	endfunction
261	
262	
263	`ifdef SYNTH_LEVEL1_COMPILE
264	`else
265	`ifdef SYNTHESIS
266	`else
267	`ifdef PRAND_VERILOG
