288	`else
289	`ifdef PRAND_VERILOG
290	        if (prand_initialized1 !== 1'b1) begin
291	            prand_no_rollpli1 = $test$plusargs("NO_ROLLPLI");
292	            if (!prand_no_rollpli1)
293	                prand_local_seed1 = {$prand_get_seed(1), 16'b0};
294	            prand_initialized1 = 1'b1;
295	        end
296	        if (prand_no_rollpli1) begin
297	            prand_inst1 = min;
298	        end else begin
299	            diff = max - min + 1;
300	            prand_inst1 = min + prand_local_seed1[47:16] % diff;
301	            // magic numbers taken from Java's random class (same as lrand48)
302	            prand_local_seed1 = prand_local_seed1 * 48'h5deece66d + 48'd11;
303	        end
304	`else
305	`ifdef PRAND_OFF
306	        prand_inst1 = min;
307	`else
308	        prand_inst1 = $RollPLI(min, max, "auto");
309	`endif
310	`endif
311	`endif
312	`endif
313	    end
314	//VCS coverage on
315	endfunction
